+    // Build: (runtime.builtins.next(&arg) catch |err| switch (err) { ... })
+    try b.emitValueCore(arg_val);
+    const arg_raw = try b.getBodyDupe();
+    const addr_expr = try std.fmt.allocPrint(alloc, "&{s}", .{arg_raw});
